mapper.update:
update orders
cancel_reason=#{cancelReason}, rejection_reason=#{rejectionReason}, cancel_time=#{cancelTime}, pay_status=#{payStatus}, pay_method=#{payMethod}, checkout_time=#{checkoutTime}, status = #{status}, delivery_time = #{deliveryTime}
where id = #{id}

mapper.select:
select t1.*, t2.id as od_id, t2.name as od_name, t2.image as od_image, t2.order_id as od_order_id, t2.dish_id as od_dish_id, t2.setmeal_id as od_setmeal_id,
       t2.dish_flavor as od_dish_flavor, t2.number as od_number, t2.amount as od_amount from order_detail t2 join orders t1 on t1.id = t2.order_id


        t1.status = #{status}


        and t1.user_id = #{userId}


order by t1.order_time desc

select t1.*, t2.id as od_id, t2.name as od_name, t2.image as od_image, t2.order_id as od_order_id, t2.dish_id as od_dish_id, t2.setmeal_id as od_setmeal_id, t2.dish_flavor as od_dish_flavor, t2.number as od_number, t2.amount as od_amount from order_detail t2 join orders t1 on t1.id = t2.order_id
t1.id = #{id}
order by t1.order_time desc

select * from orders


         number = #{number}


            and phone = #{phone}


            and order_time between #{beginTime} and #{endTime}


            and status = #{status}


order by order_time desc
